#include <stdio.h>
#include <math.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long l, d, t;
        scanf("%lld %lld %lld", &l, &d, &t);
        double x = acos((double)d / l);
        double y = l * cos(t * x);
        long long p = (long long)(y * 1000000000);
        long long q = 1000000000;
        long long r = 1;
        while (q > 0) {
            long long temp = p % q;
            p = q;
            q = temp;
            long long temp2 = r;
            r = (MOD / q) * temp2 % MOD;
            if (r < 0) r += MOD;
        }
        printf("%lld\n", (p / q) * r % MOD);
    }
    return 0;
}

