            double y = l * Math.cos(t * x);
            long p = (long)(y * 1000000000);
            long q = 1000000000;
            long r = 1;
            while (q > 0) {
                long temp = p % q;
                p = q;
                q = temp;
                long temp2 = r;
                r = (1000000007 / q) * temp2 % 1000000007;
                if (r < 0) r += 1000000007;
            }
            System.out.println((p / q) * r % 1000000007);
        }
    }
}

