const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const MOD = 1000000007;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [l, d, t] = readline().split(' ').map(Number);
    const x = Math.acos(d / l);
    const y = l * Math.cos(t * x);
    const p = Math.floor(y * 1000000000);
    const q = 1000000000;
    let r = 1;
    while (q > 0) {
        const temp = p % q;
        p = q;
        q = temp;
        const temp2 = r;
        r = Math.floor((MOD / q)) * temp2 % MOD;
        if (r < 0) r += MOD;
    }
    console.log((p / q) * r % MOD);
}

